const { action, tool_calls_so_far = 0, max_tool_calls = 100, command, files_changed = 0 } = $json;
return {
  action,
  tool_calls_so_far,
  max_tool_calls,
  command,
  files_changed,
  violations: [],
  warnings: []
};

const state = $json;
const DANGEROUS_PATTERNS = [
  { re: /rm\s+(-[rRf]+\s+)*-?[rRf]/, desc: 'recursive force delete' },
  { re: /sudo\s+rm/, desc: 'sudo delete' },
  { re: /\|\s*(ba)?sh/, desc: 'pipe to shell' },
  { re: /git\s+push\s+.*--force/, desc: 'force push' },
  { re: /git\s+reset\s+--hard/, desc: 'hard reset' },
  { re: /chmod\s+777/, desc: 'world-writable permissions' },
  { re: /drop\s+table/i, desc: 'DROP TABLE' },
  { re: /truncate\s+table/i, desc: 'TRUNCATE TABLE' },
  { re: /delete\s+from\s+\w+\s*(;|$)/i, desc: 'unconditional DELETE' },
  { re: /format\s+(drive|disk|C:)/i, desc: 'drive format' },
  { re: /dd\s+if=/, desc: 'dd disk write' },
  { re: /mkfs\./, desc: 'filesystem creation' },
  { re: />/\s*\/dev\//, desc: 'direct device write' },
];
if (state.command) {
  for (const p of DANGEROUS_PATTERNS) {
    if (p.re.test(state.command)) {
      state.violations.push({ severity: 'block', pattern: p.desc, command: state.command });
    }
  }
}
if (state.tool_calls_so_far > state.max_tool_calls) {
  state.violations.push({ severity: 'block', pattern: 'max_tool_calls_exceeded', current: state.tool_calls_so_far, limit: state.max_tool_calls });
}
return state;

const state = $json;
if (state.files_changed > 20) {
  state.warnings.push({ severity: 'warn', pattern: 'large_change_set', files: state.files_changed, tip: 'Break into smaller batches of 5-10 files' });
}
const ltmPath = '/home/timothy/Project/Arch-Mk2/ltm/store/events.jsonl';
const fs = require('fs');
const path = require('path');
if (fs.existsSync(ltmPath)) {
  const recentEvents = fs.readFileSync(ltmPath, 'utf8').split('\n').filter(Boolean).slice(-10);
  state.recent_sessions = recentEvents.map(e => { try { return JSON.parse(e); } catch (x) { return null; } }).filter(Boolean);
  // Check if similar dangerous action was attempted recently
  for (const event of state.recent_sessions) {
    if (event.type === 'guardrail_block' && event.action === state.action) {
      state.warnings.push({ severity: 'warn', pattern: 'repeat_violation', previous: event.ts, tip: 'This action was previously blocked. Consider an alternative approach.' });
    }
  }
}
return state;

const state = $json;
const ltmPath = '/home/timothy/Project/Arch-Mk2/ltm/store';
const fs = require('fs');
const path = require('path');
if (!fs.existsSync(ltmPath)) fs.mkdirSync(ltmPath, { recursive: true });
const event = {
  id: `guard_${Date.now()}`,
  ts: new Date().toISOString(),
  type: 'guardrail_block',
  action: state.action,
  violations: state.violations,
  warnings: state.warnings
};
fs.appendFileSync(path.join(ltmPath, 'events.jsonl'), JSON.stringify(event) + '\n');
return {
  allowed: false,
  action: state.action,
  violations: state.violations,
  warnings: state.warnings,
  message: `Action blocked by ${state.violations.length} guardrail violation(s)`,
  suggestion: 'Review the violations above and adjust your approach.'
};

const state = $json;
return {
  allowed: true,
  action: state.action,
  warnings: state.warnings,
  message: state.warnings.length > 0
    ? `Action allowed with ${state.warnings.length} warning(s)`
    : 'Action allowed'
};
